import React, { useState } from "react";
import airports from "../assets/airports.json"; // Make sure this file exists

const AIRLINES = [
  "American Airlines","Emirates","Qatar Airways","Singapore Airlines",
  "IndiGo","Air India","Lufthansa","British Airways","Etihad"
];

const airlineIndexMap = AIRLINES.reduce((acc, a, i) => { acc[a] = i; return acc; }, {});
const airportIndexMap = airports ? airports.reduce((acc, a, i) => { acc[a.code] = i; return acc; }, {}) : {};

export default function FlightForm({ onPredict, onLiveStart, onLiveSuccess, onLiveError }) {
  const [magicQuery, setMagicQuery] = useState("");
  const [magicLoading, setMagicLoading] = useState(false);
  const [airline, setAirline] = useState(AIRLINES[0]);
  const [source, setSource] = useState("");
  const [destination, setDestination] = useState("");
  const [date, setDate] = useState("");
  const [stops, setStops] = useState(0);
  const [loading, setLoading] = useState(false);

  const handleMagicFill = async () => {
    if (!magicQuery) return;
    try {
      setMagicLoading(true);
      const res = await fetch("http://127.0.0.1:5000/parse_flight_query", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ query: magicQuery })
      });
      const data = await res.json();
      if (data.error) throw new Error(data.error);

      if (data.source_code) setSource(data.source_code);
      if (data.destination_code) setDestination(data.destination_code);
      if (data.date) setDate(data.date);
      if (data.airline && AIRLINES.includes(data.airline)) setAirline(data.airline);
      if (data.stops !== undefined) setStops(data.stops);
    } catch (err) {
      console.error(err);
      alert("Failed to parse query with Gemini.");
    } finally {
      setMagicLoading(false);
    }
  };

  const submit = async (e) => {
    e.preventDefault();

    if (!source || !destination || !date) {
      alert("Please fill all required fields!");
      return;
    }

    if (source === destination) {
      alert("Source and destination cannot be the same.");
      return;
    }

    const dt = new Date(date);
    const day = dt.getDate();
    const month = dt.getMonth() + 1;

    const payload = {
      airline: airline,
      source: source,
      destination: destination,
      day: day,
      month: month,
      stops: Number(stops)
    };

    try {
      setLoading(true);
      const res = await fetch("http://127.0.0.1:5000/predict", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(payload)
      });
      const data = await res.json();
      if (onPredict) onPredict(data.predicted_price);
      setLoading(false);

      if (onLiveStart) onLiveStart();
      fetch("http://127.0.0.1:5000/live_price", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          source: source,
          destination: destination,
          day: day,
          month: month
        })
      }).then(r => {
        if (!r.ok) throw new Error("Live price unavailable");
        return r.json();
      }).then(liveData => {
        if (onLiveSuccess) onLiveSuccess(liveData);
      }).catch(err => {
        if (onLiveError) onLiveError(err.message);
      });

    } catch (err) {
      console.error(err);
      alert("Prediction failed!");
      setLoading(false);
    }
  };

  return (
    <form onSubmit={submit} className="bg-white dark:bg-gray-700 p-4 rounded shadow">
      <h2 className="text-xl font-semibold mb-3 dark:text-white">Enter Flight Details</h2>

      {/* Magic Fill Section */}
      <div className="mb-4 p-3 bg-purple-50 dark:bg-purple-900/20 rounded border border-purple-200 dark:border-purple-800">
        <label className="block text-sm font-medium text-purple-700 dark:text-purple-300 mb-1">
          Magic Fill with Gemini ✨
        </label>
        <div className="flex gap-2">
          <input
            type="text"
            className="flex-1 p-2 border rounded dark:bg-gray-600 dark:text-white dark:border-gray-500"
            placeholder="e.g., Flight from NYC to LAX next Friday on Delta"
            value={magicQuery}
            onChange={(e) => setMagicQuery(e.target.value)}
            onKeyDown={(e) => { if (e.key === 'Enter') { e.preventDefault(); handleMagicFill(); } }}
          />
          <button
            type="button"
            onClick={handleMagicFill}
            disabled={magicLoading}
            className="bg-purple-500 hover:bg-purple-600 text-white px-4 py-2 rounded font-medium disabled:opacity-50"
          >
            {magicLoading ? "Thinking..." : "Auto Fill"}
          </button>
        </div>
      </div>
      <hr className="my-4 border-gray-200 dark:border-gray-600" />

      <label className="block text-sm dark:text-gray-300 mt-2">Airline</label>
      <select
        className="w-full p-2 border rounded dark:bg-gray-600 dark:text-white"
        value={airline}
        onChange={(e) => setAirline(e.target.value)}
      >
        {AIRLINES.map(a => <option key={a} value={a}>{a}</option>)}
      </select>

      <label className="block text-sm dark:text-gray-300 mt-2">From (Departure)</label>
      <select
        className="w-full p-2 border rounded dark:bg-gray-600 dark:text-white"
        value={source}
        onChange={(e) => setSource(e.target.value)}
      >
        <option value="">Select Airport</option>
        {airports.map(a => (
          <option key={a.code} value={a.code}>{a.city} ({a.code}) — {a.name}</option>
        ))}
      </select>

      <label className="block text-sm dark:text-gray-300 mt-2">To (Arrival)</label>
      <select
        className="w-full p-2 border rounded dark:bg-gray-600 dark:text-white"
        value={destination}
        onChange={(e) => setDestination(e.target.value)}
      >
        <option value="">Select Airport</option>
        {airports.map(a => (
          <option key={a.code} value={a.code}>{a.city} ({a.code}) — {a.name}</option>
        ))}
      </select>

      <label className="block text-sm dark:text-gray-300 mt-2">Travel Date</label>
      <input
        type="date"
        className="w-full p-2 border rounded dark:bg-gray-600 dark:text-white"
        value={date}
        onChange={(e) => setDate(e.target.value)}
      />

      <label className="block text-sm dark:text-gray-300 mt-2">Stops</label>
      <select
        className="w-full p-2 border rounded dark:bg-gray-600 dark:text-white"
        value={stops}
        onChange={(e) => setStops(e.target.value)}
      >
        <option value={0}>Direct (0 stops)</option>
        <option value={1}>1 stop</option>
        <option value={2}>2 stops</option>
        <option value={3}>3 stops</option>
      </select>

      <button
        type="submit"
        disabled={loading}
        className="w-full mt-4 bg-blue-500 hover:bg-blue-600 text-white p-2 rounded"
      >
        {loading ? "Predicting..." : "Predict Price"}
      </button>
    </form>
  );
}
